<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\StoreGalleryImageRequest; use App\Http\Requests\Admin\UpdateGalleryImageRequest; use App\Models\GalleryImage; use App\Services\FileUploadService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class GalleryImageController extends Controller { public function index(Request $request): View { $items=GalleryImage::query()->when($request->filled('search'),fn($q)=>$q->where(fn($qq)=>$qq->where('title','like','%'.$request->search.'%')->orWhere('category','like','%'.$request->search.'%')))->when($request->filled('category'),fn($q)=>$q->where('category',$request->category))->when($request->filled('status'),fn($q)=>$q->where('status',(bool)$request->integer('status')))->ordered()->paginate(15)->withQueryString(); $categories=GalleryImage::query()->whereNotNull('category')->distinct()->orderBy('category')->pluck('category'); return view('admin.pages.gallery-images.index',compact('items','categories')); } public function create(): View { return view('admin.pages.gallery-images.form',['item'=>new GalleryImage()]); } public function store(StoreGalleryImageRequest $request, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),null,'uploads/gallery'); GalleryImage::create($data); $this->clearCache(); return redirect()->route('admin.gallery-images.index')->with('success','Gallery image created successfully.'); } public function edit(GalleryImage $galleryImage): View { return view('admin.pages.gallery-images.form',['item'=>$galleryImage]); } public function update(UpdateGalleryImageRequest $request, GalleryImage $galleryImage, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),$galleryImage->image,'uploads/gallery'); $galleryImage->update($data); $this->clearCache(); return redirect()->route('admin.gallery-images.index')->with('success','Gallery image updated successfully.'); } public function destroy(GalleryImage $galleryImage): RedirectResponse { $galleryImage->delete(); $this->clearCache(); return back()->with('success','Gallery image deleted successfully.'); } private function payload(array $data): array { $data['status']=(bool)($data['status']??false); $data['sort_order']=(int)($data['sort_order']??0); return $data; } private function clearCache(): void { foreach(['gallery_images_active_ordered','gallery_categories'] as $key) Cache::forget($key); } }
